// Priority Queue wrapper around heap
typedef struct {
 int* data;
 int* priorities;
 int size;
 int capacity;
} PriorityQueue;

// See heap implementation for core operations
// Priority queue just adds priority tracking

import heapq

# Python's heapq is a MIN-heap
# For MAX behavior, negate values

class PriorityQueue:
 """Min-priority queue using heapq"""
 def __init__(self):
 self.heap = []

 def push(self, item, priority):
 heapq.heappush(self.heap, (priority, item))

 def pop(self):
 if self.heap:
 return heapq.heappop(self.heap)[1]
 raise IndexError("Empty queue")

 def peek(self):
 return self.heap[0][1] if self.heap else None

 def __len__(self):
 return len(self.heap)

# Top K Largest Elements
def top_k_largest(nums, k):
 return heapq.nlargest(k, nums)

# Top K Smallest Elements 
def top_k_smallest(nums, k):
 return heapq.nsmallest(k, nums)

# Merge K Sorted Lists
def merge_k_sorted(lists):
 heap = []
 for i, lst in enumerate(lists):
 if lst:
 heapq.heappush(heap, (lst[0], i, 0))

 result = []
 while heap:
 val, list_idx, elem_idx = heapq.heappop(heap)
 result.append(val)
 if elem_idx + 1 < len(lists[list_idx]):
 next_val = lists[list_idx][elem_idx + 1]
 heapq.heappush(heap, (next_val, list_idx, elem_idx + 1))
 return result

# Running Median
class MedianFinder:
 def __init__(self):
 self.small = [] # max-heap (negate values)
 self.large = [] # min-heap

 def add_num(self, num):
 heapq.heappush(self.small, -num)
 heapq.heappush(self.large, -heapq.heappop(self.small))
 if len(self.large) > len(self.small):
 heapq.heappush(self.small, -heapq.heappop(self.large))

 def find_median(self):
 if len(self.small) > len(self.large):
 return -self.small[0]
 return (-self.small[0] + self.large[0]) / 2

# Demo
print("Top 3 largest:", top_k_largest([3,1,4,1,5,9,2,6], 3))
print("Merge sorted:", merge_k_sorted([[1,4,5], [1,3,4], [2,6]]))

import java.util.*;

class PriorityQueueExamples {
 // Java PriorityQueue is MIN-heap by default

 // Min Priority Queue
 public static void minPQDemo() {
 PriorityQueue<Integer> minPQ = new PriorityQueue<>();
 minPQ.offer(5);
 minPQ.offer(1);
 minPQ.offer(3);
 System.out.println("Min: " + minPQ.poll()); // 1
 }

 // Max Priority Queue
 public static void maxPQDemo() {
 PriorityQueue<Integer> maxPQ = new PriorityQueue<>(Collections.reverseOrder());
 maxPQ.offer(5);
 maxPQ.offer(1);
 maxPQ.offer(3);
 System.out.println("Max: " + maxPQ.poll()); // 5
 }

 // Top K Largest
 public static int[] topK(int[] nums, int k) {
 PriorityQueue<Integer> minHeap = new PriorityQueue<>();
 for (int num : nums) {
 minHeap.offer(num);
 if (minHeap.size() > k) minHeap.poll();
 }
 return minHeap.stream().mapToInt(i -> i).toArray();
 }

 public static void main(String[] args) {
 minPQDemo();
 maxPQDemo();
 }
}
